/**
 * Lucide-compatible shim rendering single-weight Phosphor icons as inline SVG.
 *
 * The whole app imports icons from "lucide-react"; vite.config.ts + tsconfig
 * alias that specifier to THIS file, so every icon is a Phosphor (regular weight)
 * icon under its old Lucide name — no per-file edits, reversible by removing the
 * two aliases. Inline (not the @phosphor-icons/react package) on purpose: that
 * package ships all 6 weights per icon and blew the entry-size budget; these are
 * one weight each and tree-shake per route. Regenerate via make-shim-inline.
 */
import * as React from "react";

export type LucideIcon = React.ForwardRefExoticComponent<
  Omit<React.SVGProps<SVGSVGElement>, "ref"> & { size?: number | string } & React.RefAttributes<SVGSVGElement>
>;

const make = (markup: string): LucideIcon =>
  React.forwardRef<SVGSVGElement, React.SVGProps<SVGSVGElement> & { size?: number | string }>(
    ({ size, width, height, ...props }, ref) =>
      React.createElement("svg", {
        ref,
        xmlns: "http://www.w3.org/2000/svg",
        viewBox: "0 0 256 256",
        width: width ?? size ?? "1em",
        height: height ?? size ?? "1em",
        fill: "currentColor",
        ...props,
        dangerouslySetInnerHTML: { __html: markup },
      }),
  );

